const fs = require('fs');
const path = require('path');

// 常见的 MCP 配置文件路径
const paths = [
  '/Users/orion/.cursor/mcp.json',
  '/Users/orion/.vscode/mcp.json',
  '/Users/orion/.config/mcp.json',
  '/Users/orion/.llmwork/mcp.json',
  '/Users/orion/Documents/WorkBuddy工作空间/幕布/.cursor/mcp.json',
  '/Users/orion/Documents/WorkBuddy工作空间/幕布/mcp.json',
];

for (const p of paths) {
  try {
    const content = fs.readFileSync(p, 'utf-8');
    console.log(`=== ${p} ===`);
    console.log(content);
    console.log();
  } catch (e) {
    // 文件不存在，跳过
  }
}

// 也看看环境变量
console.log('=== 环境变量 MCP 相关 ===');
for (const key of Object.keys(process.env)) {
  if (key.toLowerCase().includes('mcp')) {
    console.log(`${key}=${process.env[key].substring(0, 200)}`);
  }
}

const fs = require('fs');
const path = require('path');
const os = require('os');

// 查找所有可能的 MCP 配置文件
const homedir = os.homedir();
const searchPaths = [
  path.join(homedir, '.cursor', 'mcp.json'),
  path.join(homedir, '.windsurf', 'mcp.json'),
  path.join(homedir, '.codeium', 'mcp.json'),
  path.join(homedir, '.continue', 'mcp.json'),
  path.join(homedir, '.cline', 'mcp.json'),
  path.join(homedir, '.roocode', 'mcp.json'),
  path.join(homedir, '.github', 'copilot', 'mcp.json'),
];

for (const p of searchPaths) {
  try {
    if (fs.existsSync(p)) {
      const content = fs.readFileSync(p, 'utf-8');
      console.log(`=== ${p} ===`);
      console.log(content);
      console.log();
    }
  } catch (e) {}
}

// 也看看 ~/.workbuddy/ 下
const wbDir = path.join(homedir, '.workbuddy');
function walkDir(dir, depth = 0) {
  if (depth > 3) return;
  try {
    const files = fs.readdirSync(dir);
    for (const f of files) {
      const fp = path.join(dir, f);
      const stat = fs.statSync(fp);
      if (stat.isDirectory()) {
        walkDir(fp, depth + 1);
      } else if (f.includes('mcp') || f.includes('wechat') || f.includes('public')) {
        console.log(`=== ${fp} ===`);
        console.log(fs.readFileSync(fp, 'utf-8').substring(0, 1000));
        console.log();
      }
    }
  } catch (e) {}
}
walkDir(wbDir);

